Enter basic salary: 10000
Basic Salary = 10000.00
DA (40%)     = 4000.00
HRA (20%)    = 2000.00
Gross Salary = 16000.00

#include <stdio.h>
#include <math.h>

int main() {
    int N, isPrime = 1;
    printf("Enter N (>= 2): ");
    scanf("%d", &N);
    for (int i = 2; i <= sqrt(N); i++) {
        if (N % i == 0) {
            isPrime = 0;
            break;
        }
    }
    if (isPrime)
        printf("yes\n");
    else
        printf("No\n");
    return 0;
}

Flowchart (textual):
START
  ↓
Input: N
  ↓
isPrime = 1, i = 2
  ↓
[i <= √N?] → NO → [isPrime == 1?] → YES → Print "yes" → END
  ↓ YES                             ↓ NO
[N % i == 0?] → YES → isPrime=0 → Print "No" → END
  ↓ NO
i = i + 1 → (loop back)
